DocumentId docId = TopSolidHost.Documents.EditedDocument;
if (docId.IsEmpty) return "Aucun document ouvert.";
if (!TopSolidDraftingHost.Boms.IsBom(docId)) return "Not a BOM.";
int rootRow = TopSolidDraftingHost.Boms.GetRootRow(docId);
var children = TopSolidDraftingHost.Boms.GetRowChildrenRows(docId, rootRow);
